import{_ as o,o as i,c as t,a2 as c}from"./chunks/framework.DtwafDNl.js";const h=JSON.parse('{"title":"API Reference","description":"","frontmatter":{},"headers":[],"relativePath":"api/index.md","filePath":"api/index.md"}'),a={name:"api/index.md"};function r(s,e,d,n,p,l){return i(),t("div",null,[...e[0]||(e[0]=[c('<h1 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h1><p>Routes below are extracted from <code>backend/src/**/*controller.ts</code> decorators.</p><h2 id="flows" tabindex="-1">Flows <a class="header-anchor" href="#flows" aria-label="Permalink to &quot;Flows&quot;">​</a></h2><p><code>GET /flows</code> Description: List flows with pagination/filtering.</p><p><code>GET /flows/:id</code> Description: Get one flow detail (nodes, edges, active version).</p><p><code>POST /flows</code> Description: Create a flow.</p><p><code>PUT /flows/:id</code> Description: Update/save a flow.</p><p><code>DELETE /flows/:id</code> Description: Delete a flow.</p><p><code>GET /flows/:id/versions</code> Description: List saved versions for a flow.</p><p><code>GET /flows/:id/versions/:versionId</code> Description: Get one flow version snapshot.</p><p><code>POST /flows/:id/versions</code> Description: Create/save a new version entry.</p><p><code>POST /flows/:id/versions/:versionId/restore</code> Description: Restore a previous version into current flow state.</p><p><code>GET /flows/:id/breadcrumb</code> Description: Get parent/child breadcrumb context for subflows.</p><p><code>GET /flows/:id/tree</code> Description: Get flow tree with subflow relationships.</p><h2 id="extensions" tabindex="-1">Extensions <a class="header-anchor" href="#extensions" aria-label="Permalink to &quot;Extensions&quot;">​</a></h2><p><code>GET /extensions</code> Description: List SIP extensions.</p><p><code>POST /extensions</code> Description: Create extension.</p><p><code>PUT /extensions/:id</code> Description: Update extension.</p><p><code>DELETE /extensions/:id</code> Description: Delete extension.</p><h2 id="trunks" tabindex="-1">Trunks <a class="header-anchor" href="#trunks" aria-label="Permalink to &quot;Trunks&quot;">​</a></h2><p><code>GET /trunks</code> Description: List SIP trunks.</p><p><code>POST /trunks</code> Description: Create trunk.</p><p><code>PUT /trunks/:id</code> Description: Update trunk.</p><p><code>DELETE /trunks/:id</code> Description: Delete trunk.</p><p><code>POST /trunks/:id/test</code> Description: Run trunk test.</p><p><code>POST /trunks/:id/test-outbound</code> Description: Start outbound trunk test call.</p><p><code>POST /trunks/:id/test-inbound</code> Description: Start inbound trunk test call.</p><p><code>GET /trunks/:id/test-call/:testCallId/status</code> Description: Read trunk test call status.</p><h2 id="inbound" tabindex="-1">Inbound <a class="header-anchor" href="#inbound" aria-label="Permalink to &quot;Inbound&quot;">​</a></h2><p><code>GET /inbound-routes</code> Description: List inbound DID routes.</p><p><code>POST /inbound-routes</code> Description: Create inbound route.</p><p><code>PUT /inbound-routes/:id</code> Description: Update inbound route.</p><p><code>DELETE /inbound-routes/:id</code> Description: Delete inbound route.</p><h2 id="queues" tabindex="-1">Queues <a class="header-anchor" href="#queues" aria-label="Permalink to &quot;Queues&quot;">​</a></h2><p><code>GET /queues</code> Description: List queues.</p><p><code>POST /queues</code> Description: Create queue.</p><p><code>PATCH /queues/:id</code> Description: Update queue.</p><p><code>DELETE /queues/:id</code> Description: Delete queue.</p><h2 id="operators" tabindex="-1">Operators <a class="header-anchor" href="#operators" aria-label="Permalink to &quot;Operators&quot;">​</a></h2><p><code>GET /operators</code> Description: List operators with computed status.</p><p><code>POST /operators</code> Description: Create operator.</p><p><code>PUT /operators/:id</code> Description: Update operator.</p><p><code>DELETE /operators/:id</code> Description: Delete operator.</p><h2 id="campaigns" tabindex="-1">Campaigns <a class="header-anchor" href="#campaigns" aria-label="Permalink to &quot;Campaigns&quot;">​</a></h2><p><code>GET /campaigns</code> Description: List campaigns.</p><p><code>GET /campaigns/:id</code> Description: Get campaign detail.</p><p><code>POST /campaigns</code> Description: Create campaign.</p><p><code>PATCH /campaigns/:id</code> Description: Update campaign.</p><p><code>DELETE /campaigns/:id</code> Description: Delete campaign.</p><p><code>POST /campaigns/:id/contacts/upload</code> Description: Upload/import campaign contacts CSV.</p><p><code>GET /campaigns/:id/contacts</code> Description: List campaign contacts.</p><p><code>GET /campaigns/:id/contacts/:contactId/attempts</code> Description: List attempt history for one campaign contact.</p><p><code>POST /campaigns/:id/schedule</code> Description: Move campaign to scheduled state.</p><p><code>POST /campaigns/:id/stop</code> Description: Stop/cancel running or scheduled campaign.</p><p><code>GET /campaigns/:id/progress</code> Description: Read campaign progress counters.</p><h2 id="recordings" tabindex="-1">Recordings <a class="header-anchor" href="#recordings" aria-label="Permalink to &quot;Recordings&quot;">​</a></h2><p><code>GET /recordings</code> Description: List call recordings.</p><p><code>POST /recordings/internal</code> Description: Internal recording persistence endpoint (token-protected header).</p><p><code>GET /recordings/:id</code> Description: Get recording metadata.</p><p><code>GET /recordings/:id/stream</code> Description: Stream recording content.</p><p><code>GET /recordings/:id/download</code> Description: Download recording file.</p><p><code>DELETE /recordings/:id</code> Description: Delete recording.</p><h2 id="capture" tabindex="-1">Capture <a class="header-anchor" href="#capture" aria-label="Permalink to &quot;Capture&quot;">​</a></h2><p><code>GET /capture/packets/:callId</code> Description: Get SIP capture packets for call id.</p><p><code>GET /capture/export/dialog/:callId</code> Description: Export one call SIP dialog.</p><p><code>GET /capture/export/bulk</code> Description: Bulk export SIP capture data.</p><h2 id="diagnostics" tabindex="-1">Diagnostics <a class="header-anchor" href="#diagnostics" aria-label="Permalink to &quot;Diagnostics&quot;">​</a></h2><p><code>GET /diagnostics/health</code> Description: Get diagnostics health summary.</p><p><code>GET /diagnostics/resources</code> Description: Get runtime resource metrics.</p><p><code>POST /diagnostics/trunks/:id/test</code> Description: Trigger diagnostics trunk test.</p><p><code>POST /diagnostics/trunks/test-all</code> Description: Trigger diagnostics for all trunks.</p><p><code>GET /diagnostics/registrations</code> Description: Get current SIP registration snapshot.</p><p><code>GET /diagnostics/failures</code> Description: Get recent call/registration failures.</p><p><code>GET /diagnostics/sip-messages</code> Description: List SIP signaling messages.</p><p><code>GET /diagnostics/sip-messages/:callId</code> Description: List SIP signaling messages for one call.</p><h2 id="firewall" tabindex="-1">Firewall <a class="header-anchor" href="#firewall" aria-label="Permalink to &quot;Firewall&quot;">​</a></h2><p><code>GET /firewall/config</code> Description: Get firewall config.</p><p><code>PUT /firewall/config</code> Description: Update firewall config.</p><p><code>GET /firewall/preflight</code> Description: Get firewall preflight status (including fail2ban availability).</p><p><code>GET /firewall/blocked-ips</code> Description: List currently blocked IPs.</p><p><code>POST /firewall/blocked-ips</code> Description: Manually block an IP.</p><p><code>DELETE /firewall/blocked-ips/:ip</code> Description: Unblock an IP.</p><p><code>POST /firewall/whitelist</code> Description: Add whitelist IP.</p><p><code>DELETE /firewall/whitelist/:ip</code> Description: Remove whitelist IP.</p><p><code>GET /firewall/events</code> Description: List firewall event history.</p><p><code>GET /firewall/stats</code> Description: Get firewall stats payload.</p><h2 id="vpn" tabindex="-1">VPN <a class="header-anchor" href="#vpn" aria-label="Permalink to &quot;VPN&quot;">​</a></h2><p><code>GET /vpn/status</code> Description: Read VPN install/runtime status.</p><p><code>GET /vpn/peers</code> Description: List active VPN peers.</p><p><code>POST /vpn/peers</code> Description: Create VPN peer.</p><p><code>GET /vpn/peers/:id/config</code> Description: Get peer config text.</p><p><code>GET /vpn/peers/:id/qr</code> Description: Get peer config QR PNG.</p><p><code>DELETE /vpn/peers/:id</code> Description: Revoke one VPN peer.</p><p><code>DELETE /vpn</code> Description: Remove WireGuard container/runtime.</p><p><code>GET /vpn/relay-guide</code> Description: Get step-by-step relay setup guide payload.</p><p><code>POST /vpn/relay-config</code> Description: Generate relay config from VPS key/IP.</p><h2 id="backup" tabindex="-1">Backup <a class="header-anchor" href="#backup" aria-label="Permalink to &quot;Backup&quot;">​</a></h2><p><code>POST /backup</code> Description: Create backup archive.</p><p><code>GET /backup</code> Description: List backup history.</p><p><code>DELETE /backup/:id</code> Description: Delete backup entry and file.</p><p><code>GET /backup/:id/download</code> Description: Download backup archive.</p><p><code>POST /backup/restore</code> Description: Restore backup archive (DB and/or recordings).</p><p><code>GET /backup/config</code> Description: Get backup scheduler config.</p><p><code>PUT /backup/config</code> Description: Update backup scheduler config.</p><h2 id="config" tabindex="-1">Config <a class="header-anchor" href="#config" aria-label="Permalink to &quot;Config&quot;">​</a></h2><p><code>GET /config/host</code> Description: Get host SIP provisioning values (<code>hostIp</code>, <code>sipPort</code>).</p><h2 id="audio" tabindex="-1">Audio <a class="header-anchor" href="#audio" aria-label="Permalink to &quot;Audio&quot;">​</a></h2><p><code>GET /audio</code> Description: List audio files.</p><p><code>GET /audio/voices</code> Description: List TTS voices.</p><p><code>GET /audio/:id</code> Description: Get one audio file record.</p><p><code>POST /audio/upload</code> Description: Upload audio file.</p><p><code>POST /audio/tts</code> Description: Generate and save TTS audio.</p><p><code>POST /audio/tts/preview</code> Description: Generate TTS preview.</p><p><code>DELETE /audio/:id</code> Description: Delete audio file.</p><h2 id="additional-controllers-present-in-source" tabindex="-1">Additional controllers present in source <a class="header-anchor" href="#additional-controllers-present-in-source" aria-label="Permalink to &quot;Additional controllers present in source&quot;">​</a></h2><h3 id="call-logs" tabindex="-1">Call logs <a class="header-anchor" href="#call-logs" aria-label="Permalink to &quot;Call logs&quot;">​</a></h3><p><code>GET /call-logs</code> Description: List call logs.</p><p><code>GET /call-logs/:callUuid/trace</code> Description: Get node-level trace for a call UUID.</p><h3 id="callbacks" tabindex="-1">Callbacks <a class="header-anchor" href="#callbacks" aria-label="Permalink to &quot;Callbacks&quot;">​</a></h3><p><code>GET /callbacks</code> Description: List callback jobs.</p><p><code>GET /callbacks/:id</code> Description: Get callback job.</p><p><code>POST /callbacks/:id/execute</code> Description: Execute callback immediately.</p><p><code>POST /callbacks/:id/cancel</code> Description: Cancel callback job.</p><h3 id="contact-numbers" tabindex="-1">Contact numbers <a class="header-anchor" href="#contact-numbers" aria-label="Permalink to &quot;Contact numbers&quot;">​</a></h3><p><code>GET /contact-numbers</code> Description: List contact numbers.</p><p><code>GET /contact-numbers/:id</code> Description: Get contact number.</p><p><code>POST /contact-numbers</code> Description: Create contact number.</p><p><code>PATCH /contact-numbers/:id</code> Description: Update contact number.</p><p><code>DELETE /contact-numbers/:id</code> Description: Delete contact number.</p><h3 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h3><p><code>GET /templates</code> Description: List flow templates.</p><p><code>POST /templates/:id/import</code> Description: Import template into flows.</p><h3 id="preflight" tabindex="-1">Preflight <a class="header-anchor" href="#preflight" aria-label="Permalink to &quot;Preflight&quot;">​</a></h3><p><code>POST /preflight/run</code> Description: Run preflight checks.</p><p><code>GET /preflight/history</code> Description: Get preflight history.</p><h3 id="quality" tabindex="-1">Quality <a class="header-anchor" href="#quality" aria-label="Permalink to &quot;Quality&quot;">​</a></h3><p><code>GET /quality/:callId</code> Description: Get call quality metrics for call id.</p><h3 id="asterisk-logs" tabindex="-1">Asterisk logs <a class="header-anchor" href="#asterisk-logs" aria-label="Permalink to &quot;Asterisk logs&quot;">​</a></h3><p><code>GET /asterisk/logs</code> Description: Read paged Asterisk log lines.</p><h3 id="health" tabindex="-1">Health <a class="header-anchor" href="#health" aria-label="Permalink to &quot;Health&quot;">​</a></h3><p><code>GET /health</code> Description: Basic health endpoint.</p>',141)])])}const D=o(a,[["render",r]]);export{h as __pageData,D as default};
